export type Credit = {
  role: string;
  name: string;
};

export type TrackMusicVideo = {
  has_music_video: boolean;
  youtube_url: string | null;
  youtube_video_id: string | null;
  youtube_status: string;
  video_type: string | null;
  confidence: string;
  notes?: string;
  non_youtube_evidence?: unknown;
};

export type DiscographyTrack = {
  num: number;
  title: string;
  duration: string;
  credits: Credit[];
  musicVideoUrl?: string | null;
  videoEmbed?: string | null;
  hasVideo: boolean;
  disc_number?: number;
  track_number?: number;
  display_title?: string;
  primary_artists?: string[];
  featured_artists?: string[];
  credits_status?: string;
  music_video?: TrackMusicVideo | null;
  track_source?: string;
  track_confidence?: string;
};

export type DiscographyReleaseSource = {
  page: string;
  refs: string[];
  confidence: string;
};

export type CoverAsset = {
  kind: "image" | "gif" | "video";
  src: string;
  poster?: string;
};

export type PlatformLink = {
  value: string;
  valid: boolean;
};

import { ALBUM_STREAMING_ROUTES_BY_TITLE } from "./albumStreamingRoutes";
import { REQUESTED_ALBUM_TRACKLISTS_BY_TITLE, type RequestedAlbumTracklist } from "./albumTracklistsRequested";

export type PlatformLinks = {
  spotify: PlatformLink;
  appleMusic: PlatformLink;
  youtube: PlatformLink;
};

export type StreamingStats = {
  source: string;
  status: string;
  date: string;
};

export type RawDiscographyRelease = {
  id: string;
  title: string;
  year: number;
  type: string;
  releaseDate: string | null;
  source: DiscographyReleaseSource;
  coverUrl?: string;
  coverAsset?: CoverAsset;
  links: PlatformLinks;
  streamingStats: StreamingStats | null;
  credits: Credit[];
  tracklist: DiscographyTrack[];
  videoEmbed: string | null;
};

export type DiscographyItem = {
  id: string;
  title: string;
  year: number;
  type: string;
  releaseDate: string | null;
  sourcePage: string;
  sourceRefs: string[];
  sourceConfidence: string;
  coverUrl: string;
  coverAsset: CoverAsset;
  platformLinks: PlatformLinks;
  streamingStats: StreamingStats | null;
  credits: Credit[];
  tracklist: DiscographyTrack[];
  videoEmbed: string | null;
};

const link = (value = ""): PlatformLink => ({
  value,
  valid: Boolean(value),
});

const linkSet = (): PlatformLinks => ({
  spotify: link(),
  appleMusic: link(),
  youtube: link(),
});

const t = (
  num: number,
  title: string,
  duration: string,
  credits: Credit[] = [],
  musicVideoUrl?: string | null,
  videoEmbed: string | null = null,
): DiscographyTrack => ({
  num,
  title,
  duration,
  credits,
  musicVideoUrl: musicVideoUrl ?? null,
  videoEmbed,
  hasVideo: Boolean(musicVideoUrl),
});

const release = (item: RawDiscographyRelease): DiscographyItem => {
  const streamingRoute = ALBUM_STREAMING_ROUTES_BY_TITLE[item.title];
  const platformLinks = streamingRoute
    ? {
        spotify: link(streamingRoute.urls.direct.spotify ?? streamingRoute.urls.fallbackSearch.spotify ?? ""),
        appleMusic: link(streamingRoute.urls.direct.appleMusic ?? streamingRoute.urls.fallbackSearch.appleMusic ?? ""),
        youtube: link(streamingRoute.urls.direct.youtubeMusic ?? streamingRoute.urls.fallbackSearch.youtubeMusic ?? ""),
      }
    : item.links;

  return {
    id: item.id,
    title: item.title,
    year: item.year,
    type: item.type,
    releaseDate: item.releaseDate,
    sourcePage: item.source.page,
    sourceRefs: item.source.refs,
    sourceConfidence: item.source.confidence,
    coverUrl: item.coverAsset?.poster ?? item.coverUrl ?? "",
    coverAsset: item.coverAsset ?? { kind: "image", src: item.coverUrl ?? "" },
    platformLinks,
    streamingStats: item.streamingStats,
    credits: item.credits,
    tracklist: item.tracklist,
    videoEmbed: item.videoEmbed,
  };
};


