const normalizeAlbumTitle = (value: string) =>
  value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const requestedTrackToDiscographyTrack = (track: RequestedAlbumTracklist["tracks"][number]): DiscographyTrack => ({
  num: track.track_number,
  title: track.title,
  display_title: track.display_title ?? track.title,
  duration: track.duration,
  credits: track.credits,
  musicVideoUrl: track.music_video?.youtube_url ?? null,
  videoEmbed: track.music_video?.youtube_video_id ? `https://www.youtube.com/embed/${track.music_video.youtube_video_id}` : track.music_video?.youtube_url ?? null,
  hasVideo: Boolean(track.music_video?.has_music_video && track.music_video.youtube_url),
  disc_number: track.disc_number,
  track_number: track.track_number,
  primary_artists: track.primary_artists,
  featured_artists: track.featured_artists,
  credits_status: track.credits_status,
  music_video: track.music_video,
  track_source: track.track_source,
  track_confidence: track.track_confidence,
});

const mergeRequestedAlbumTracklists = (releases: RawDiscographyRelease[]): RawDiscographyRelease[] => {
  const merged = new Map<string, RawDiscographyRelease>();

  for (const releaseItem of releases) {
    merged.set(normalizeAlbumTitle(releaseItem.title), releaseItem);
  }

  for (const album of Array.from(REQUESTED_ALBUM_TRACKLISTS_BY_TITLE ? Object.values(REQUESTED_ALBUM_TRACKLISTS_BY_TITLE) : [])) {
    const key = normalizeAlbumTitle(album.title);
    const existing = merged.get(key);
    const requestedTracklist = album.tracks.map(requestedTrackToDiscographyTrack);

    if (existing) {
      merged.set(key, {
        ...existing,
        tracklist: requestedTracklist,
      });
      continue;
    }

    merged.set(key, {
      id: album.id,
      title: album.title,
      year: album.year,
      type: album.project_type,
      releaseDate: album.release_date,
      source: {
        page: album.source_urls[0] ?? album.urls?.official_smart_link ?? album.urls?.primary_router ?? "",
        refs: ["requestedAlbumTracklists"],
        confidence: album.verification_status,
      },
      coverUrl: "",
      links: linkSet(),
      streamingStats: null,
      credits: [],
      tracklist: requestedTracklist,
      videoEmbed: null,
    });
  }

  return Array.from(merged.values()).sort(
    (left, right) => new Date(right.releaseDate ?? `${right.year}-01-01`).getTime() - new Date(left.releaseDate ?? `${left.year}-01-01`).getTime(),
  );
};

export const DISCOGRAPHY: DiscographyItem[] = mergeRequestedAlbumTracklists([...RAW_DISCOGRAPHY_RELEASES]).map(release);

